 1	import React, { FC, useState } from 'react';
 2	
 3	import Loading from '@kubevirt-utils/components/Loading/Loading';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  Bullseye,
 7	  DrawerActions,
 8	  DrawerHead,
 9	  DrawerPanelBody,
10	  Text,
11	  TreeView,
12	  TreeViewDataItem,
13	} from '@patternfly/react-core';
14	
15	import useFilteredTreeView from '../hooks/useFilteredTreeView';
16	
17	import CreateProject from './CreateProject';
18	import PanelToggleButton from './PanelToggleButton';
19	import TreeViewCollapseExpand from './TreeViewCollapseExpand';
20	import TreeViewToolbar from './TreeViewToolbar';
21	
22	type TreeViewContentProps = {
23	  isOpen: boolean;
24	  isSwitchDisabled: boolean;
25	  loaded: boolean;
26	  onSelect: (_event: React.MouseEvent, treeViewItem: TreeViewDataItem) => void;
27	  selectedTreeItem: TreeViewDataItem;
28	  toggleDrawer: () => void;
29	  treeData: TreeViewDataItem[];
30	};
31	
32	const TreeViewContent: FC<TreeViewContentProps> = ({
33	  isOpen,
34	  isSwitchDisabled,
35	  loaded,
36	  onSelect,
37	  selectedTreeItem,
38	  toggleDrawer,
39	  treeData,
40	}) => {
41	  const { t } = useKubevirtTranslation();
42	  const [showAll, setShowAll] = useState<boolean>();
43	  const { filteredTreeData, onSearch } = useFilteredTreeView(treeData, setShowAll);
44	
45	  if (!loaded) {
46	    return (
47	      <Bullseye>
48	        <Loading />
49	      </Bullseye>
50	    );
51	  }
52	
53	  if (!isOpen) {
54	    return (
55	      <PanelToggleButton
56	        className="vms-tree-view__action"
57	        isOpen={isOpen}
58	        toggleDrawer={toggleDrawer}
59	      />
60	    );
61	  }
62	
63	  return (
64	    <>
65	      <TreeViewToolbar
66	        closeComponent={
67	          <PanelToggleButton
68	            className="vms-tree-view__close-button"
69	            isOpen={isOpen}
70	            toggleDrawer={toggleDrawer}
71	          />
72	        }
73	        isSwitchDisabled={isSwitchDisabled}
74	        onSearch={onSearch}
75	      />
76	      <DrawerHead className="vms-tree-view__header-section">
77	        <Text className="vms-tree-view__title">
78	          <TreeViewCollapseExpand setShowAll={setShowAll} showAll={showAll} />
79	          {t('Projects')}
80	        </Text>
81	        <DrawerActions>
82	          <CreateProject />
83	        </DrawerActions>
84	      </DrawerHead>
85	      <DrawerPanelBody className="vms-tree-view-body">
86	        <TreeView
87	          activeItems={[selectedTreeItem]}
88	          allExpanded={showAll}
89	          data={filteredTreeData}
90	          hasBadges={loaded}
91	          hasSelectableNodes
92	          onSelect={onSelect}
93	        />
94	      </DrawerPanelBody>
95	    </>
96	  );
97	};
98	
99	export default TreeViewContent;

